--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(30) NOT NULL COMMENT 'DH-YYYYMMDD-XXXX',
  `customer_id` int(10) unsigned NOT NULL,
  `salesperson_id` int(10) unsigned NOT NULL COMMENT 'Nhân viên tạo đơn',
  `warehouse_id` int(10) unsigned NOT NULL,
  `group_id` int(10) unsigned DEFAULT NULL,
  `source_type` enum('sales','collaborator') NOT NULL DEFAULT 'sales' COMMENT 'sales=bán trực tiếp; collaborator=quản lý là salesperson_id, CTV=collaborator_user_id',
  `collaborator_user_id` int(10) unsigned DEFAULT NULL COMMENT 'CTV khi source_type=collaborator',
  `status` enum('pending','shipping','completed','cancelled') NOT NULL DEFAULT 'pending',
  `shipping_address` text DEFAULT NULL,
  `carrier_service` varchar(100) DEFAULT NULL,
  `shipping_fee` decimal(12,2) NOT NULL DEFAULT 0.00,
  `ship_payer` enum('shop','customer') NOT NULL DEFAULT 'customer' COMMENT 'shop=shop trả ship; customer=khách trả ship (mặc định)',
  `deposit` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Tiền đặt cọc',
  `customer_collect` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Thu khách',
  `shop_collect` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Shop thu',
  `salesperson_absorbed_amount` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Amount absorbed by salesperson (customer shortfall); deducted from commission later',
  `payment_method` varchar(50) DEFAULT 'cash',
  `subtotal` decimal(15,2) NOT NULL DEFAULT 0.00,
  `discount` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Giảm giá đơn',
  `tax_amount` decimal(15,2) NOT NULL DEFAULT 0.00,
  `total_amount` decimal(15,2) NOT NULL DEFAULT 0.00,
  `note` text DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `idx_orders_code` (`code`),
  KEY `idx_orders_customer` (`customer_id`),
  KEY `idx_orders_salesperson` (`salesperson_id`),
  KEY `idx_orders_warehouse` (`warehouse_id`),
  KEY `idx_orders_status` (`status`),
  KEY `idx_orders_created_at` (`created_at`),
  KEY `idx_orders_group` (`group_id`),
  KEY `idx_orders_collaborator` (`collaborator_user_id`),
  CONSTRAINT `fk_orders_collaborator_user` FOREIGN KEY (`collaborator_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_orders_customer` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`),
  CONSTRAINT `fk_orders_group` FOREIGN KEY (`group_id`) REFERENCES `groups` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_orders_salesperson` FOREIGN KEY (`salesperson_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_orders_warehouse` FOREIGN KEY (`warehouse_id`) REFERENCES `warehouses` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=161 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

